class Solution {
    public int calculate(String s) {
        int len = s.length();
        int currNum = 0;
        char operation = '+';
        int[] stack = new int[len];
        int top = 0;

        for (int i = 0; i < len; i++) {
            if (Character.isDigit(s.charAt(i))) {
                currNum = currNum * 10 + s.charAt(i) - '0';
            }
            if ((!Character.isDigit(s.charAt(i)) && !Character.isWhitespace(s.charAt(i))) || i == len - 1) {
                switch (operation) {
                    case '+':
                        stack[top++] = currNum;
                        break;
                    case '-':
                        stack[top++] = -currNum;
                        break;
                    case '*':
                        stack[top - 1] *= currNum;
                        break;
                    case '/':
                        stack[top - 1] /= currNum;
                        break;
                }
                operation = s.charAt(i);
                currNum = 0;
            }
        }

        int result = 0;
        while (top > 0) {
            result += stack[--top];
        }
        return result;
    }
}
